const STORAGE_KEY="magalu_system_user",userName=document.getElementById("user-name"),userRole=document.getElementById("user-role"),userIdMagalu=document.getElementById("user-id-magalu"),userPontos=document.getElementById("user-pontos"),userTempo=document.getElementById("user-tempo"),userCheckins=document.getElementById("user-checkins"),userCpf=document.getElementById("user-cpf"),userRegiao=document.getElementById("user-regiao"),userLoja=document.getElementById("user-loja"),userTurma=document.getElementById("user-turma"),userTransfer=document.getElementById("user-transfer"),estandesList=document.getElementById("estandes-list"),logoutButton=document.getElementById("logout-button");function redirectToLogin(){window.location.replace(new URL("../login/",window.location.href))}function renderVisitedStands(e){if(estandesList.innerHTML="",!Array.isArray(e)||0===e.length){const e=document.createElement("li");return e.className="empty-state",e.textContent="Nenhum estande visitado ainda.",void estandesList.appendChild(e)}e.forEach(e=>{const t=document.createElement("li");t.textContent=e.nome||"Estande sem nome",estandesList.appendChild(t)})}const rawUser=localStorage.getItem(STORAGE_KEY);if(rawUser){const e=JSON.parse(rawUser);userName.textContent=e.nome||"Usuario",userRole.textContent=`${e.cargo||"Sem cargo"} · ${e.loja||"Sem loja"}`,userIdMagalu.textContent=e.id_magalu||"-",userPontos.textContent=String(e.pontos||0),userTempo.textContent=String(e.tempo||0),userCheckins.textContent=String(e.totalCheckins||0),userCpf.textContent=e.cpf||"-",userRegiao.textContent=e.regiao||"-",userLoja.textContent=e.loja||"-",userTurma.textContent=e.turma||"-",userTransfer.textContent=e.transfer?"Sim":"Nao",renderVisitedStands(e.estandesVisitados)}else redirectToLogin();logoutButton.addEventListener("click",()=>{localStorage.removeItem(STORAGE_KEY),redirectToLogin()});